ALTER TABLE `posts` ADD COLUMN IF NOT EXISTS `coverImage` text;
ALTER TABLE `posts` ADD COLUMN IF NOT EXISTS `status` enum('draft','published') DEFAULT 'draft' NOT NULL;
ALTER TABLE `posts` MODIFY COLUMN `content` text NOT NULL;
ALTER TABLE `posts` MODIFY COLUMN `authorId` int NOT NULL

